#include <iostream>
#include <string>

class Counter {
private:
    int count;

public:
    Counter(int initial_count = 0) : count(initial_count) {}

    int get_count() const {
        return count;
    }

    void set_count(int val) {
        count = val;
    }

    Counter& operator++() {
        ++count;
        return *this;
    }

    Counter operator--(int) {
        Counter temp = *this;
        --count;
        return temp;
    }
};

void run_test(const std::string& description, int initial_val, int expected_prefix_val, int expected_postfix_old_val, int expected_postfix_new_val, int expected_chained_prefix_val) {
    std::cout << "--- Test: " << description << " ---\n";

    Counter c1(initial_val);
    ++c1;
    std::cout << "Initial: " << initial_val << ", After ++prefix: " << c1.get_count() << "\n";
    if (c1.get_count() == expected_prefix_val) {
        std::cout << "++prefix PASSED (internal increment)\n";
    } else {
        std::cout << "++prefix FAILED (internal increment) (Expected: " << expected_prefix_val << ", Got: " << c1.get_count() << ")\n";
    }

    Counter c_chain_test(initial_val);
    (++c_chain_test).set_count(expected_chained_prefix_val);
    std::cout << "Initial: " << initial_val << ", After (++c).set_count(" << expected_chained_prefix_val << "): " << c_chain_test.get_count() << "\n";
    if (c_chain_test.get_count() == expected_chained_prefix_val) {
        std::cout << "++prefix return reference SEMANTICS PASSED\n";
    } else {
        std::cout << "++prefix return reference SEMANTICS FAILED (Expected: " << expected_chained_prefix_val << ", Got: " << c_chain_test.get_count() << ")\n";
    }

    Counter c2(initial_val);
    Counter old_val_c2 = c2--;
    std::cout << "Initial: " << initial_val << ", After postfix-- (old value): " << old_val_c2.get_count() << ", (new value): " << c2.get_count() << "\n";
    if (old_val_c2.get_count() == expected_postfix_old_val && c2.get_count() == expected_postfix_new_val) {
        std::cout << "postfix-- PASSED\n";
    } else {
        std::cout << "postfix-- FAILED (Expected old: " << expected_postfix_old_val << ", Got: " << old_val_c2.get_count() << "; Expected new: " << expected_postfix_new_val << ", Got: " << c2.get_count() << ")\n";
    }
    std::cout << "\n";
}

int main() {
    run_test("Basic operations with 5", 5, 6, 5, 4, 10);
    run_test("Operations with 0", 0, 1, 0, -1, 5);
    run_test("Operations with negative 3", -3, -2, -3, -4, 0);
    return 0;
}
